// Get the input from the webhook using .first() instead of .item
const input = $('POST /api/v1/haze-vector-math1').first().json.body;

// Get all stations from the previous node (Fetch 3 Nearest Stations)
const stations = $input.all().map(i => i.json);

function calculateHaversine(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180) * Math.cos(lat2*Math.PI/180) * Math.sin(dLon/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

// "Upwind" = the nearest station whose bearing-from-user roughly matches
// the direction the wind is blowing FROM (wind_degrees is meteorological
// convention: direction wind blows FROM).
function bearing(lat1, lon1, lat2, lon2) {
  const toRad = d => d * Math.PI / 180;
  const y = Math.sin(toRad(lon2-lon1)) * Math.cos(toRad(lat2));
  const x = Math.cos(toRad(lat1))*Math.sin(toRad(lat2)) - Math.sin(toRad(lat1))*Math.cos(toRad(lat2))*Math.cos(toRad(lon2-lon1));
  return (toRad === null) ? 0 : (Math.atan2(y, x) * 180 / Math.PI + 360) % 360;
}

// NEAREST STATION - This is the user's current location AQI
const nearest = stations[0];
const distanceToNearest = nearest.distance_km || calculateHaversine(input.lat, input.lon, nearest.lat, nearest.lon);

// Find UPWIND STATION - Where the air is coming FROM
let upwind = stations[0];
let bestDiff = 361;
for (const s of stations) {
  const b = bearing(input.lat, input.lon, s.lat, s.lon);
  const diff = Math.min(Math.abs(b - s.wind_degrees), 360 - Math.abs(b - s.wind_degrees));
  if (diff < bestDiff) { bestDiff = diff; upwind = s; }
}

const windSpeed = upwind.wind_speed_kmh;
let safety_status, estimated_clearance_hours;

if (!windSpeed || parseFloat(windSpeed) < 5) {
  safety_status = 'Unsafe / Stagnant';
  estimated_clearance_hours = null;
} else {
  const distanceKm = calculateHaversine(input.lat, input.lon, upwind.lat, upwind.lon);
  const timeToArrival = distanceKm / parseFloat(windSpeed);
  safety_status = upwind.last_aqi < 100 ? 'Clearing Trend' : 'Incoming Plume Warning';
  estimated_clearance_hours = Math.round(timeToArrival * 10) / 10;
}

// Forecast trend based on upwind station
let forecast_trend = null;
if (upwind.last_pm25 != null && upwind.forecast_pm25_tomorrow != null) {
  const delta = parseFloat(upwind.forecast_pm25_tomorrow) - parseFloat(upwind.last_pm25);
  forecast_trend = delta > 10 ? 'worsening' : delta < -10 ? 'improving' : 'stable';
}

// Wind confidence
let wind_confidence = 'normal';
if (upwind.station_wind_speed_ms != null && windSpeed != null) {
  const stationKmh = parseFloat(upwind.station_wind_speed_ms) * 3.6;
  if (Math.abs(stationKmh - parseFloat(windSpeed)) > 10) wind_confidence = 'uncertain';
}

// Check if forecast is unhealthy
const forecastUnhealthy = upwind.forecast_pm25_tomorrow != null && parseFloat(upwind.forecast_pm25_tomorrow) > 55;
const dominantPollutant = upwind.dominant_pollutant || nearest.dominant_pollutant || 'Unknown';

return [{
  json: {
    userId: input.userId || null,
    lat: input.lat,
    lon: input.lon,
    requireLLM: input.requireLLM || false,

    // === NEAREST STATION (Current Location - what the user is breathing NOW) ===
    nearest_station: nearest.station_name,
    nearest_aqi: nearest.last_aqi ? parseInt(nearest.last_aqi) : null,
    nearest_pm25: nearest.last_pm25 ? parseInt(nearest.last_pm25) : null,
    nearest_pm10: nearest.last_pm10 ? parseInt(nearest.last_pm10) : null,
    nearest_distance_km: Math.round(distanceToNearest * 10) / 10,
    nearest_dominant_pollutant: nearest.dominant_pollutant || null,
    nearest_temperature: nearest.temperature ? parseFloat(nearest.temperature) : null,
    nearest_humidity: nearest.humidity ? parseFloat(nearest.humidity) : null,
    nearest_forecast_pm25_tomorrow: nearest.forecast_pm25_tomorrow ? parseInt(nearest.forecast_pm25_tomorrow) : null,
    nearest_forecast_pm10_tomorrow: nearest.forecast_pm10_tomorrow ? parseInt(nearest.forecast_pm10_tomorrow) : null,

    // === UPWIND STATION (Air Source - where air is coming FROM) ===
    upwind_station: upwind.station_name,
    upwind_aqi: upwind.last_aqi ? parseInt(upwind.last_aqi) : null,
    upwind_pm25: upwind.last_pm25 ? parseInt(upwind.last_pm25) : null,
    upwind_pm10: upwind.last_pm10 ? parseInt(upwind.last_pm10) : null,
    upwind_distance_km: Math.round(calculateHaversine(input.lat, input.lon, upwind.lat, upwind.lon) * 10) / 10,

    // === Weather data (from upwind) ===
    wind_speed_kmh: windSpeed ? parseFloat(windSpeed) : null,
    wind_degrees: upwind.wind_degrees ? parseFloat(upwind.wind_degrees) : null,
    wind_confidence: wind_confidence,

    // === Safety status ===
    safety_status: safety_status,
    estimated_clearance_hours: estimated_clearance_hours,

    // === Forecast ===
    forecast_trend: forecast_trend,
    forecast_pm25_tomorrow: upwind.forecast_pm25_tomorrow ? parseInt(upwind.forecast_pm25_tomorrow) : null,
    forecast_pm10_tomorrow: upwind.forecast_pm10_tomorrow ? parseInt(upwind.forecast_pm10_tomorrow) : null,
    forecast_unhealthy: forecastUnhealthy,

    // === Additional data ===
    dominant_pollutant: dominantPollutant,
    temperature: upwind.temperature ? parseFloat(upwind.temperature) : null,
    humidity: upwind.humidity ? parseFloat(upwind.humidity) : null,
    pressure: upwind.pressure ? parseFloat(upwind.pressure) : null,
    o3: upwind.o3 ? parseFloat(upwind.o3) : null,
    no2: upwind.no2 ? parseFloat(upwind.no2) : null,
    so2: upwind.so2 ? parseFloat(upwind.so2) : null,
    co: upwind.co ? parseFloat(upwind.co) : null,
    forecast_uvi_tomorrow: upwind.forecast_uvi_tomorrow ? parseFloat(upwind.forecast_uvi_tomorrow) : null,
    last_updated: upwind.last_updated
  }
}];

const calcData = $('Advection-Dispersion Calc1').item.json;
const llmOutput = $input.first().json;

// Extract the fallback timestamp cleanly if it exists under either naming convention
const lastUpdatedTime =  calcData.last_updated || calcData.updated_at || null;

// Extract the LLM response
let responseData = {};

try {
  const rawText = llmOutput.text || llmOutput.response || JSON.stringify(llmOutput);
  // Try to parse JSON
  responseData = typeof rawText === 'string' ? JSON.parse(rawText) : rawText;
} catch (e) {
  // If JSON parsing fails, build fallback
  responseData = {
    message: `Air quality at your location: AQI ${calcData.nearest_aqi}, PM2.5 ${calcData.nearest_pm25} µg/m³. ${calcData.safety_status}.`,
    structured: {
      current_aqi: calcData.nearest_aqi,
      current_pm25: calcData.nearest_pm25,
      current_pm10: calcData.nearest_pm10,
      current_station: calcData.nearest_station,
      temperature: calcData.temperature,
      humidity: calcData.humidity,
      wind_speed: calcData.wind_speed_kmh,
      upwind_station: calcData.upwind_station,
      upwind_aqi: calcData.upwind_aqi,
      status: calcData.safety_status,
      clearance_hours: calcData.estimated_clearance_hours,
      forecast_trend: calcData.forecast_trend,
      forecast_pm25_tomorrow: calcData.forecast_pm25_tomorrow,
      recommendations: ["Check back for updates"],
      last_updated: lastUpdatedTime,
    }
  };
}

// Ensure we have both message and structured data
const message = responseData.message || `Air quality at your location: AQI ${calcData.nearest_aqi}`;
const structured = responseData.structured || {};

// Inject the validated timestamp into the LLM-generated structure if it isn't already there
if (!structured.last_updated) {
  structured.last_updated = lastUpdatedTime;
}

return [{
  json: {
    // User location
    user_lat: calcData.lat,
    user_lon: calcData.lon,

    // Current AQI data
    aqi: calcData.nearest_aqi,
    pm25: calcData.nearest_pm25,
    pm10: calcData.nearest_pm10,
    nearest_station: calcData.nearest_station,

    // Upwind forecast
    upwind_station: calcData.upwind_station,
    upwind_aqi: calcData.upwind_aqi,

    // Safety
    safety_status: calcData.safety_status,
    estimated_clearance_hours: calcData.estimated_clearance_hours,

    // Weather
    temperature: calcData.temperature,
    humidity: calcData.humidity,
    wind_speed_kmh: calcData.wind_speed_kmh,
    forecast_trend: calcData.forecast_trend,
    forecast_pm25_tomorrow: calcData.forecast_pm25_tomorrow,

    // The beautiful message from LLM
    message: message,

    // Structured data for frontend components
    structured: structured,
    last_updated: lastUpdatedTime,
  }
}];

const rows = $input.all();
const resolvedUserId = rows.length > 0 ? rows[0].json.id : null;

return [{
  json: {
    ...$('Advection-Dispersion Calc1').item.json,
    resolvedUserId
  }
}];
